import { Worker } from 'bullmq';
import { sendgrid } from '../lib/sendgrid';

export const emailWorker = new Worker('emails', async (job) => {
  const { to, orderId, template } = job.data;
  // BUG: if this resolves but the job later times out, retry re-sends
  await sendgrid.send({ to, templateId: template, dynamicData: { orderId } });
  return { sent: true };
}, { connection, concurrency: 20 });

import { Queue } from 'bullmq';
export const emailQueue = new Queue('emails', { connection });

export function enqueueConfirmation(orderId: string, to: string) {
  // BUG: no jobId, so BullMQ generates a random one — no natural dedupe
  return emailQueue.add('confirmation', { to, orderId, template: 'd-confirm' }, {
