import { Worker } from 'bullmq';
import { sendgrid } from '../lib/sendgrid';
import { redis } from '../lib/redis';
import { db } from '../lib/db';

async function alreadySent(orderId: string, template: string) {
  const row = await db.sentEmails.findUnique({ where: { orderId_template: { orderId, template } } });
  return row?.messageId ?? null;
}

export const emailWorker = new Worker('emails', async (job) => {
  const { to, orderId, template } = job.data;
  const ledgerKey = `sent:${orderId}:${template}`;
  const existing = await alreadySent(orderId, template);
  if (existing) return { sent: true, messageId: existing, dedup: true };
  const claimed = await redis.set(ledgerKey, job.id ?? '1', 'EX', 86400, 'NX');
  if (!claimed) {
    const committed = await alreadySent(orderId, template);
    if (committed) return { sent: true, messageId: committed, dedup: true };
    throw new Error('claim held by another attempt, retry');
  }
  const res = await sendgrid.send({ to, templateId: template, dynamicData: { orderId } });
  await db.sentEmails.create({ data: { orderId, template, messageId: res.messageId } });
  return { sent: true, messageId: res.messageId };
}, { connection, concurrency: 20 });

