import { Kafka } from 'kafkajs';
const consumer = kafka.consumer({ groupId: 'settlement-v2' });
const MAX_RETRY = 3;

await consumer.run({
  eachMessage: async ({ topic, partition, message }) => {
    const evt = JSON.parse(message.value!.toString());
    for (let attempt = 0; attempt <= MAX_RETRY; attempt++) {
      try {
        await ledger.post(evt, { idempotencyKey: `${evt.merchantId}:${evt.eventId}` });
        return;
      } catch (err: any) {
        if (attempt === MAX_RETRY) {
          await producer.send({ topic: 'dlq.settlement', messages: [{
            key: message.key,
            value: message.value,
            headers: { origTopic: topic, origPartition: String(partition), origOffset: message.offset, error: err.message },
          }]});
          return; // commit advances past the poison message
        }
        await sleep(200 * 2 ** attempt + Math.random() * 100);
      }
    }
  },
});

export async function replayDlq(filter: (h: Record<string,string>) => boolean, reason: string, actor: string) {
  const c = kafka.consumer({ groupId: `replay-${Date.now()}` });
  await c.subscribe({ topic: 'dlq.settlement', fromBeginning: true });
  await c.run({ eachMessage: async ({ message }) => {
    const headers = Object.fromEntries(Object.entries(message.headers ?? {}).map(([k,v]) => [k, v!.toString()]));
    if (!filter(headers)) return;
    await db.replayAudit.create({ data: { actor, reason, eventKey: message.key!.toString(), at: new Date() } });
    await producer.send({ topic: headers.origTopic, messages: [{ key: message.key, value: message.value }] });
  }});
}

