import { Worker } from 'bullmq';
import sharp from 'sharp';
import { MemoryGate } from './memory-gate';

const gate = new MemoryGate({ highWaterBytes: 1.5e9, maxInFlight: 6 });

export const w = new Worker('resize', async (job) => {
  await gate.acquire();
  try {
    const buf = await s3.getObject(job.data.key);
    const out = await sharp(buf, { limitInputPixels: 24_000_000, sequentialRead: true })
      .resize(400, 400, { fit: 'cover' })
      .jpeg({ quality: 82 })
      .toBuffer();
    await s3.putObject(job.data.outKey, out);
  } finally {
    gate.release();
  }
}, { connection, concurrency: 6 });

export class MemoryGate {
  private inFlight = 0;
  private waiters: Array<() => void> = [];
  constructor(private opts: { highWaterBytes: number; maxInFlight: number }) {}
  async acquire() {
    while (this.inFlight >= this.opts.maxInFlight || process.memoryUsage().rss > this.opts.highWaterBytes) {
      await new Promise<void>((r) => this.waiters.push(r));
    }
    this.inFlight++;
  }
  release() {
    this.inFlight--;
    const next = this.waiters.shift();
    if (next) next();
  }
}

