test('burst of large images keeps RSS bounded', async () => {
  const jobs = Array.from({ length: 200 }, (_, i) => ({ data: { key: `big-${i}`, outKey: `t-${i}` } }));
  let peak = 0;
  const t = setInterval(() => { peak = Math.max(peak, process.memoryUsage().rss); }, 25);
  await Promise.all(jobs.map((j: any) => w.processFn(j)));
