    backoffStrategy: (attempts: number) => {
      const base = 1000, cap = 5 * 60_000;
      const expo = Math.min(cap, base * 2 ** attempts);
      return Math.floor(base + Math.random() * (expo - base)); // decorrelated jitter
    },
