import { Worker } from 'bullmq';
export const w = new Worker('webhooks', async (job) => {
  const { endpoint, payload } = job.data;
  const res = await fetch(endpoint, { method: 'POST', body: JSON.stringify(payload), signal: AbortSignal.timeout(10_000) });
  if (res.status >= 500 || res.status === 429) throw new Error(`retryable ${res.status}`);
  if (!res.ok) return { dropped: res.status }; // 4xx non-retryable
}, {
  connection,
  concurrency: 50,
  limiter: { max: 100, duration: 1000, groupKey: 'endpoint' },
});

test('retry delays are spread, not synchronized', () => {
  const strat = (a: number) => { const base=1000, cap=300000, expo=Math.min(cap, base*2**a); return base + Math.random()*(expo-base); };
  const delays = Array.from({ length: 1000 }, () => strat(3));
  const min = Math.min(...delays), max = Math.max(...delays);
  expect(max - min).toBeGreaterThan(3000); // wide spread, not a single value
});

export async function claimJob(tx: Tx) {
  // BUG: every worker locks the same oldest row, serializing all pollers
  const job = await tx.query(
    `SELECT * FROM jobs WHERE status='pending' ORDER BY created_at LIMIT 1 FOR UPDATE`);
  if (!job.rows[0]) return null;
  await tx.query(`UPDATE jobs SET status='running' WHERE id=$1`, [job.rows[0].id]);
  return job.rows[0];
}

export async function claimBatch(tx: Tx, workerId: string, size = 10) {
  const res = await tx.query(
    `UPDATE jobs SET status='running', locked_by=$1, lease_until=now()+interval '60 seconds'
     WHERE id IN (
       SELECT id FROM jobs WHERE status='pending'
       ORDER BY created_at LIMIT $2 FOR UPDATE SKIP LOCKED
     ) RETURNING *`,
    [workerId, size]);
  return res.rows;
}

export async function heartbeat(tx: Tx, id: string) {
  await tx.query(`UPDATE jobs SET lease_until=now()+interval '60 seconds' WHERE id=$1 AND status='running'`, [id]);
}

export async function reclaimExpired(db: Db) {
  // requeue jobs whose worker died and lease expired
  const r = await db.query(
    `UPDATE jobs SET status='pending', locked_by=NULL
     WHERE status='running' AND lease_until < now() RETURNING id`);
  return r.rowCount;
}

test('two workers claim disjoint rows', async () => {
  await seedPending(100);
  const [a, b] = await Promise.all([
    db.tx((t) => claimBatch(t, 'w1', 10)),
    db.tx((t) => claimBatch(t, 'w2', 10)),
  ]);
  const ids = new Set([...a, ...b].map((r) => r.id));
  expect(ids.size).toBe(a.length + b.length); // no overlap
});

