import { Queue } from 'bullmq';
export const interactive = new Queue('exports.interactive', { connection });
export const paidBulk = new Queue('exports.paid-bulk', { connection });
export const freeBulk = new Queue('exports.free-bulk', { connection });

export function enqueueExport(job: ExportJob) {
  const target = job.interactive ? interactive : job.tier === 'paid' ? paidBulk : freeBulk;
  return target.add('export', job, { group: { id: job.customerId } });
}

// Weighted round-robin: interactive guaranteed >=60% of worker slots
const lanes = [
  { q: interactive, weight: 6 },
  { q: paidBulk, weight: 3 },
  { q: freeBulk, weight: 1 },
];
let cursor = 0;
export function nextLane() {
  const expanded = lanes.flatMap((l) => Array(l.weight).fill(l.q));
  return expanded[cursor++ % expanded.length];
}

import { Worker } from 'bullmq';
