await consumer.run({
  autoCommit: false,
  eachBatch: async ({ batch, resolveOffset, commitOffsetsIfNecessary, heartbeat, isRunning, isStale }) => {
    const msgs = batch.messages;
    const rows = msgs.map(parse);
    // write FIRST, commit AFTER success
    await timescale.upsertBatch(rows);
