export type Step = { name: string; run: (ctx: Ctx) => Promise<void>; compensate: (ctx: Ctx) => Promise<void> };

export async function runSaga(sagaId: string, steps: Step[], ctx: Ctx) {
  const done: Step[] = [];
  try {
    for (const s of steps) {
      if (await isStepDone(sagaId, s.name)) { done.push(s); continue; }
      await s.run(ctx);
      await markStepDone(sagaId, s.name);
      done.push(s);
    }
  } catch (err) {
    for (const s of done.reverse()) {
      await s.compensate(ctx); // reverse-order compensation
      await markStepCompensated(sagaId, s.name);
    }
    throw err;
  }
}

CREATE TABLE saga_steps (
  saga_id text NOT NULL,
  name    text NOT NULL,
  status  text NOT NULL CHECK (status IN ('done','compensated')),
