const WINDOW = 20_000; // max resident child jobs
export const w = new Worker('campaigns', async (job) => {
  const { campaignId, cursor = '0' } = job.data;
  const depth = await sendQueue.getWaitingCount();
  if (depth > WINDOW) {
    // backpressure: reschedule self, don't pile on
    await campaignQueue.add('fanout', { campaignId, cursor }, { delay: 2000 });
    return;
  }
  const page = await loadRecipientsAfter(campaignId, cursor, 5000); // keyset stream
  await sendQueue.addBulk(page.rows.map((r) => ({ name: 'send', data: { campaignId, email: r.email } })));
  if (page.nextCursor) {
    await campaignQueue.add('fanout', { campaignId, cursor: page.nextCursor }, { delay: 0 });
  }
}, { connection });

export async function loadRecipientsAfter(campaignId: string, cursor: string, limit: number) {
  // keyset pagination avoids loading all 12M rows
  const rows = await pg.query(
    `SELECT id, email FROM campaign_recipients WHERE campaign_id=$1 AND id > $2 ORDER BY id LIMIT $3`,
    [campaignId, cursor, limit]);
  const nextCursor = rows.length === limit ? rows[rows.length - 1].id : null;
  return { rows, nextCursor };
}

