export class RedisCircuit {
  constructor(private redis: Redis, private key: string, private opts: { failures: number; windowSec: number; cooldownSec: number }) {}
  async state(): Promise<'closed'|'open'|'half'> {
    const openUntil = Number(await this.redis.get(`${this.key}:openUntil`) ?? 0);
    if (Date.now() < openUntil) return 'open';
    if (openUntil && Date.now() >= openUntil) return 'half';
    return 'closed';
  }
  async onSuccess() { await this.redis.del(`${this.key}:fails`, `${this.key}:openUntil`); }
  async onFailure() {
    const fails = await this.redis.incr(`${this.key}:fails`);
    await this.redis.expire(`${this.key}:fails`, this.opts.windowSec);
    if (fails >= this.opts.failures) {
      await this.redis.set(`${this.key}:openUntil`, Date.now() + this.opts.cooldownSec * 1000);
    }
  }
}

const breaker = new RedisCircuit(redis, 'cb:bank', { failures: 50, windowSec: 30, cooldownSec: 60 });
export const w = new Worker('recon', async (job) => {
  const state = await breaker.state();
  if (state === 'open') { await w.rateLimit(5000); throw Worker.RateLimitError(); }
  try {
    const res = await bankApi.getTransactions(job.data.accountId);
    await breaker.onSuccess();
    await reconcile(res, job.data);
  } catch (err) {
    await breaker.onFailure();
    throw err;
  }
}, { connection, concurrency: 30, attempts: 8, backoff: { type: 'exponential', delay: 2000 } });

test('breaker opens and stops downstream calls', async () => {
  jest.spyOn(bankApi, 'getTransactions').mockRejectedValue(new Error('503'));
  const calls = jest.spyOn(bankApi, 'getTransactions');
  for (let i = 0; i < 200; i++) { try { await w.processFn({ data: { accountId: 'a' } } as any); } catch {} }
  // after threshold, breaker is open and rate-limits further calls
  expect(await breaker.state()).toBe('open');
  const before = calls.mock.calls.length;
  for (let i = 0; i < 100; i++) { try { await w.processFn({ data: { accountId: 'a' } } as any); } catch {} }
  expect(calls.mock.calls.length - before).toBeLessThan(5); // not 100
});

