export async function createPickTicket(order: Order) {
  // upsert on order_id makes SQS duplicate deliveries idempotent
  await pg.query(
    `INSERT INTO pick_tickets(order_id, payload, created_at) VALUES ($1,$2,now())
     ON CONFLICT (order_id) DO NOTHING`,
    [order.id, JSON.stringify(order)]);
  const created = await pg.query(`SELECT 1 FROM pick_tickets WHERE order_id=$1`, [order.id]);
  await wms.ensurePick(order.id); // also idempotent by order_id
  return created.rowCount === 1;
}

