func handleSafely(ctx context.Context, m kafka.Message) (commit bool) {
    defer func() {
        if rec := recover(); rec != nil {
            log.Printf("panic on offset %d: %v", m.Offset, rec)
            toDLQ(ctx, m, fmt.Sprintf("panic: %v", rec))
            commit = true // commit past the poison message
        }
    }()
    var evt ShipmentEvent
    if err := json.Unmarshal(m.Value, &evt); err != nil || evt.Shipment == nil {
        toDLQ(ctx, m, "unmarshal/validation failed")
        return true
    }
    process(evt.Shipment.ID, evt.Status)
    return true
}

func toDLQ(ctx context.Context, m kafka.Message, reason string) {
    dlqWriter.WriteMessages(ctx, kafka.Message{
        Key:   m.Key,
        Value: m.Value,
        Headers: []kafka.Header{
            {Key: "orig_topic", Value: []byte(m.Topic)},
            {Key: "orig_partition", Value: []byte(strconv.Itoa(m.Partition))},
            {Key: "orig_offset", Value: []byte(strconv.FormatInt(m.Offset, 10))},
            {Key: "reason", Value: []byte(reason)},
        },
    })
}

func Reprocess(ctx context.Context, filter func(reason string) bool) error {
    dr := kafka.NewReader(kafka.ReaderConfig{Brokers: brokers, Topic: "shipments.dlq", GroupID: "reprocess"})
    for {
        m, err := dr.ReadMessage(ctx)
        if err != nil { return err }
        reason := headerVal(m, "reason")
        if !filter(reason) { continue }
        mainWriter.WriteMessages(ctx, kafka.Message{Key: m.Key, Value: m.Value})
    }
}

func TestPoisonMessageDoesNotPanicAndCommits(t *testing.T) {
    m := kafka.Message{Value: []byte("{not json"), Offset: 42}
    commit := handleSafely(context.Background(), m)
    if !commit { t.Fatal("poison message should commit to advance offset") }
    if dlqCount() != 1 { t.Fatalf("expected 1 DLQ message, got %d", dlqCount()) }
}

