function scheduleNext(reminder: Reminder) {
  // BUG: freezes the offset at creation; wrong after DST changes
  const offsetMs = reminder.utcOffsetMinutes * 60_000;
  const fireAtUtc = nextLocalMidnight(reminder) - offsetMs;
  return reminderQueue.add('fire', { id: reminder.id }, { delay: fireAtUtc - Date.now() });
}

import { DateTime } from 'luxon';
export function computeNextFireUtc(reminder: Reminder, from = DateTime.utc()): DateTime {
  // anchor to the user's wall-clock time in their IANA zone using CURRENT rules
  let next = DateTime.fromObject(
    { hour: reminder.localHour, minute: reminder.localMinute },
    { zone: reminder.ianaZone });
  if (next <= from.setZone(reminder.ianaZone)) next = next.plus({ days: reminder.cadenceDays });
  return next.toUTC();
}
export function scheduleNext(reminder: Reminder) {
  const fireAt = computeNextFireUtc(reminder);
  return reminderQueue.add('fire', { id: reminder.id }, { delay: fireAt.toMillis() - Date.now() });
}

