const CHUNK = 5000;
export async function backfill(jobName = 'denorm-2026') {
  let cursor = await getCheckpoint(jobName); // resume point
  for (;;) {
    const rows = await db.query(
      `SELECT id, raw FROM records WHERE id > $1 ORDER BY id LIMIT $2`, [cursor, CHUNK]);
    if (rows.length === 0) break;
    await db.tx(async (t) => {
      for (const r of rows) {
        await t.query(`UPDATE records SET denorm = $1 WHERE id = $2`, [compute(r.raw), r.id]);
      }
      // checkpoint committed in the SAME tx as the chunk's writes
      await t.query(
        `INSERT INTO backfill_checkpoints(job, last_id) VALUES ($1,$2)
         ON CONFLICT (job) DO UPDATE SET last_id = EXCLUDED.last_id`,
        [jobName, rows[rows.length - 1].id]);
    });
    cursor = rows[rows.length - 1].id;
    await throttle(); // keep replication lag bounded
  }
}

CREATE TABLE backfill_checkpoints (
  job     text PRIMARY KEY,
  last_id bigint NOT NULL,
  updated_at timestamptz NOT NULL DEFAULT now()
);

export async function throttle() {
  const lag = await replicationLagSeconds();
  // back off if the replica falls behind, protecting live traffic
  await sleep(lag > 5 ? 2000 : 200);
}

test('crash mid-run resumes from checkpoint without redoing work', async () => {
  await seedRecords(50_000);
  await runBackfillUntil('denorm-2026', stopAtId(20_000)); // simulate crash
  const cp1 = await getCheckpoint('denorm-2026');
  expect(cp1).toBeGreaterThanOrEqual(20_000);
  const writesBefore = updateCount();
  await backfill('denorm-2026'); // resumes
  expect(updateCount() - writesBefore).toBeLessThanOrEqual(30_000 + CHUNK); // didn't redo first 20k
});

