export async function withDeadline<T>(ms: number, fn: () => Promise<T>): Promise<T> {
  let timer: NodeJS.Timeout;
  const guard = new Promise<never>((_, rej) => { timer = setTimeout(() => rej(new Error('job deadline exceeded')), ms); });
  try {
    return await Promise.race([fn(), guard]);
  } finally {
    clearTimeout(timer!);
  }
}

// trip a per-endpoint breaker after repeated timeouts so we stop wasting slots
export async function recordTimeout(endpoint: string) {
  const n = await redis.incr(`to:${endpoint}`);
