channel.consume('claims', async (msg) => {
  const claim = JSON.parse(msg.content.toString());
  const redeliveries = Number(msg.properties.headers?.['x-redelivery-count'] ?? 0);
  try {
    await db.tx(async (t) => {
      await t.query(
        `INSERT INTO claims(claim_id, payload) VALUES ($1,$2) ON CONFLICT (claim_id) DO NOTHING`,
        [claim.id, JSON.stringify(claim)]);
    });
    channel.ack(msg); // ack AFTER commit
  } catch (err) {
    if (redeliveries >= 5) {
      channel.nack(msg, false, false); // to dead-letter exchange
    } else {
      // requeue with an incremented redelivery count via republish to keep ordering simple
      channel.nack(msg, false, true);
    }
  }
}, { noAck: false });

