async function acquireWithToken(key: string, ttl: number): Promise<number | null> {
  const ok = await redis.set(key, '1', 'EX', ttl, 'NX');
  if (!ok) return null;
  return Number(await redis.incr(`${key}:token`)); // monotonic fencing token
}

