export class BoundedBuffer<T> {
  private routine: T[] = [];
  private critical: T[] = [];
  constructor(private maxRoutine: number) {}
  push(item: T, isCritical: boolean) {
    if (isCritical) { this.critical.push(item); return; }
    if (this.routine.length >= this.maxRoutine) { this.routine.shift(); metrics.increment('telemetry_dropped'); }
    this.routine.push(item);
  }
  drain(n: number): T[] {
    // criticals first, then routine
    const out = this.critical.splice(0, n);
    if (out.length < n) out.push(...this.routine.splice(0, n - out.length));
    return out;
  }
}

import { BoundedBuffer } from './bounded-buffer';
const buffer = new BoundedBuffer<Msg>(200_000); // memory cap on routine data
mqtt.on('message', (_t, payload) => {
  const msg = JSON.parse(payload.toString());
  buffer.push(msg, msg.type === 'alarm'); // alarms are critical, never dropped
});
setInterval(async () => {
