export function reportBufferDepth(buffer: { routineLen: number; criticalLen: number }) {
  metrics.gauge('telemetry_routine_buffer', buffer.routineLen);
  metrics.gauge('telemetry_critical_buffer', buffer.criticalLen);
}

test('burst keeps memory bounded and never drops alarms', async () => {
  const buf = new BoundedBuffer<Msg>(1000);
  for (let i = 0; i < 100_000; i++) buf.push({ type: 'sample', v: i }, false);
  buf.push({ type: 'alarm', v: 1 }, true);
  expect(buf['routine'].length).toBeLessThanOrEqual(1000); // bounded
  const drained = buf.drain(2000);
  expect(drained.some((m) => m.type === 'alarm')).toBe(true); // alarm preserved
});
